import os
from web3 import Web3
import json

# Let Docker tell it where the blockchain is, otherwise default to local
BLOCKCHAIN_URL = os.getenv("BLOCKCHAIN_URL", "http://127.0.0.1:7545")
print(f"Connecting to blockchain at: {BLOCKCHAIN_URL}")

w3 = Web3(Web3.HTTPProvider(BLOCKCHAIN_URL))

# ... rest of your deploy.py code remains exactly the same ...

with open("contract_abi.json", "r") as f:
    abi = json.load(f)

# Put your massive 0x bytecode string here!
bytecode = ""

print("Deploying contract to Ganache...")

# Build and send the deployment transaction
Contract = w3.eth.contract(abi=abi, bytecode=bytecode)
tx_hash = Contract.constructor().transact({'from': w3.eth.accounts[0]})

# Wait for the blockchain to mine the transaction
tx_receipt = w3.eth.wait_for_transaction_receipt(tx_hash)
new_address = tx_receipt.contractAddress

with open("address.txt", "w") as f:
    f.write(new_address)

print(f"Success! Contract deployed -> {new_address}")